def variants_json(slug):
    sizes = [400, 800, 1200]
    parts = []
    for w in sizes:
        h = w * 9 // 16
        url = f"/images/articles/{slug}-{w}w.webp"
        parts.append(
            f'{{"width":{w},"format":"webp","url":"{url}","size":{w*h//4}}}'
        )
    return "[" + ",".join(parts) + "]"

