def make_slug(title_tag, i):
    return f"{title_tag}-{i+1}" if i > 0 else title_tag

lines = [
    "-- ============================================================",
    "-- Migration: 028 — Seed dummy articles (15 entries)",
    "-- Generated by scripts/generate_article_seed.py",
    "-- ============================================================",
    "",
    "DO $$ DECLARE",
]

# Declare category ID variables
cat_slugs = set(a["category_slug"] for a in ARTICLES)
for v in VARIATIONS:
    cat_slugs.add(v[1])
for cs in cat_slugs:
    var = cs.replace("-", "_")
    lines.append(f"  v_cat_{var} UUID;")

# Declare tag ID variables
all_tags = set()
for a in ARTICLES:
    for t in a["tags"]:
        all_tags.add(t)
for v in VARIATIONS:
    all_tags.add(v[6])
for t in all_tags:
    var = t.replace("-", "_")
    lines.append(f"  v_tag_{var} UUID;")

lines += [
    "BEGIN",
    "",
    "  -- Fetch category IDs",
]
for cs in cat_slugs:
    var = cs.replace("-", "_")
    lines.append(f"  SELECT id INTO v_cat_{var} FROM article_categories WHERE slug = '{cs}';")

lines += ["", "  -- Insert tags (idempotent)"]
tag_names = {
    "solo-leveling": "Solo Leveling", "manhwa": "Manhwa", "completed": "Completed",
    "overgeared": "Overgeared", "anime": "Anime", "adaptation": "Adaptation",
    "tower-of-god": "Tower of God", "tbate": "TBATE", "reaper": "Reaper of the Drifting Moon",
    "orv": "Omniscient Reader", "manhwa-market": "Market", "nano-machine": "Nano Machine",
    "mount-hua": "Return of Mount Hua", "top-10": "Top 10", "regression-fantasy": "Regression Fantasy",
    "sword-bitten": "Axed", "kakao": "Kakao Webtoon", "march-picks": "Monthly Picks",
    "murim-login": "Murim Login",
}
for t in all_tags:
    name = tag_names.get(t, t.replace("-", " ").title())
    var = t.replace("-", "_")
    lines.append(f"  INSERT INTO article_tags (id, name, slug) VALUES (gen_random_uuid(), '{name}', '{t}') ON CONFLICT (slug) DO NOTHING;")
    lines.append(f"  SELECT id INTO v_tag_{var} FROM article_tags WHERE slug = '{t}';")

# Insert the 2 base articles
lines += ["", "  -- Insert base articles and media assets"]
article_ids = []
for a in ARTICLES:
    aid = str(uuid.uuid4())
    mid = str(uuid.uuid4())
    article_ids.append((aid, a))
    img = a["image_slug"]
    cat_var = a["category_slug"].replace("-", "_")
    variants = variants_json(img)
    lines.append(f"""
  INSERT INTO media_assets (id, slug, asset_type, content_hash, original_width, original_height, aspect_ratio, mime_type, dominant_color, blur_data_uri, variants, r2_base_path)
  VALUES ('{mid}', '{img}', 'article-image', md5('{img}'), 1200, 675, 1.7778, 'image/webp', '{a["dominant_color"]}', '', '{variants}', '/images/articles')
  ON CONFLICT (slug, asset_type, content_hash) DO NOTHING;

  INSERT INTO articles (id, slug, title, subtitle, body, excerpt, featured_image_id, category_id, publication_state, publish_date, featured, reading_time_minutes, word_count)
  SELECT '{aid}', '{a["slug"]}', $art${a["title"]}$art$, $art${a["subtitle"]}$art$,
    $art${a["body"]}$art$, $art${a["excerpt"]}$art$,
    (SELECT id FROM media_assets WHERE slug = '{img}' AND asset_type = 'article-image' LIMIT 1),
    v_cat_{cat_var}, 'published', '{a["publish_date"]}', {'TRUE' if a["featured"] else 'FALSE'}, {a["reading_time"]}, {a["word_count"]}
  WHERE NOT EXISTS (SELECT 1 FROM articles WHERE slug = '{a["slug"]}');""")
    for tag in a["tags"]:
        tvar = tag.replace("-", "_")
        lines.append(f"  INSERT INTO article_tag_assignments (article_id, tag_id) VALUES ('{aid}', v_tag_{tvar}) ON CONFLICT DO NOTHING;")

# Insert variation articles
lines += ["", "  -- Insert variation articles"]
for i, v in enumerate(VARIATIONS):
    title, cat_slug, img_slug, dom_color, pub_date, featured, tag_key = v
    aid = str(uuid.uuid4())
    mid = str(uuid.uuid4())
    slug = f"{tag_key}-news-{i+1}"
    cat_var = cat_slug.replace("-", "_")
    tag_var = tag_key.replace("-", "_")
    excerpt = f"Latest update on {title.lower()} — stay tuned for more details as they emerge from the source."
    body = f"## {title}\n\nThis is developing news from the manhwa and webtoon industry. We will continue to update this article as more information becomes available.\n\n## Background\n\nThe community has been closely following this story. Reactions have been mixed but largely enthusiastic.\n\n## What This Means\n\nFor fans of the genre, this represents a significant development in an already exciting year for manhwa."
    variants = variants_json(img_slug)
    word_count = 60
    reading_time = 2
    lines.append(f"""
  INSERT INTO media_assets (id, slug, asset_type, content_hash, original_width, original_height, aspect_ratio, mime_type, dominant_color, blur_data_uri, variants, r2_base_path)
  VALUES ('{mid}', '{img_slug}-v{i}', 'article-image', md5('{img_slug}-v{i}'), 1200, 675, 1.7778, 'image/webp', '{dom_color}', '', '{variants}', '/images/articles')
  ON CONFLICT (slug, asset_type, content_hash) DO NOTHING;

  INSERT INTO articles (id, slug, title, subtitle, body, excerpt, featured_image_id, category_id, publication_state, publish_date, featured, reading_time_minutes, word_count)
  SELECT '{aid}', '{slug}', $art${title}$art$, 'Latest update from the manhwa world',
    $art${body}$art$, $art${excerpt}$art$,
    (SELECT id FROM media_assets WHERE slug = '{img_slug}-v{i}' AND asset_type = 'article-image' LIMIT 1),
    v_cat_{cat_var}, 'published', '{pub_date}', FALSE, {reading_time}, {word_count}
  WHERE NOT EXISTS (SELECT 1 FROM articles WHERE slug = '{slug}');""")
    lines.append(f"  INSERT INTO article_tag_assignments (article_id, tag_id) VALUES ('{aid}', v_tag_{tag_var}) ON CONFLICT DO NOTHING;")

lines += ["", "END $$;", ""]

sql = "\n".join(lines)
with open(OUT, "w", encoding="utf-8") as f:
    f.write(sql)

print(f"Written: {OUT}")
print(f"Total articles: {len(ARTICLES) + len(VARIATIONS)}")
